diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 7bff13d59528..775f1a4ad865 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -1850,6 +1850,46 @@ static Value *simplifyAndOrOfFCmps(const SimplifyQuery &Q, FCmpInst *LHS,
                  : ConstantInt::getBool(LHS->getType(), !IsAnd);
   }

+  // For ordered comparisons with the same operand and different constants:
+  //   OR can drop the stricter bound:  (X < C0) | (X < C1) -> X < max(C0, C1)
+  //                                  (X > C0) | (X > C1) -> X > min(C0, C1)
+  //   AND can drop the weaker bound: (X < C0) & (X < C1) -> X < min(C0, C1)
+  //                                  (X > C0) & (X > C1) -> X > max(C0, C1)
+  if (FCmpInst::isOrdered(PredL) && FCmpInst::isOrdered(PredR)) {
+    CmpInst::Predicate CanonPredL = PredL, CanonPredR = PredR;
+    Value *VarL = LHS0, *VarR = RHS0;
+    const APFloat *CL = nullptr, *CR = nullptr;
+
+    if (match(LHS1, m_APFloat(CL))) {
+      // Keep predicate orientation with variable on operand 0.
+    } else if (match(LHS0, m_APFloat(CL))) {
+      CanonPredL = CmpInst::getSwappedPredicate(PredL);
+      VarL = LHS1;
+    }
+
+    if (match(RHS1, m_APFloat(CR))) {
+      // Keep predicate orientation with variable on operand 0.
+    } else if (match(RHS0, m_APFloat(CR))) {
+      CanonPredR = CmpInst::getSwappedPredicate(PredR);
+      VarR = RHS1;
+    }
+
+    if (CL && CR && VarL == VarR && CanonPredL == CanonPredR &&
+        (CanonPredL == FCmpInst::FCMP_OLT || CanonPredL == FCmpInst::FCMP_OLE ||
+         CanonPredL == FCmpInst::FCMP_OGT || CanonPredL == FCmpInst::FCMP_OGE)) {
+      APFloat::cmpResult Cmp = CL->compare(*CR);
+      if (Cmp == APFloat::cmpEqual)
+        return LHS;
+
+      bool LHSLess = Cmp == APFloat::cmpLessThan;
+      bool UseLHS = (CanonPredL == FCmpInst::FCMP_OLT ||
+                     CanonPredL == FCmpInst::FCMP_OLE)
+                        ? (IsAnd ? LHSLess : !LHSLess)
+                        : (IsAnd ? !LHSLess : LHSLess);
+      return UseLHS ? static_cast<Value *>(LHS) : static_cast<Value *>(RHS);
+    }
+  }
+
   return nullptr;
 }

