      // Keep predicate orientation with variable on operand 0.
    } else if (match(LHS0, m_APFloat(CL))) {
      CanonPredL = CmpInst::getSwappedPredicate(PredL);
      VarL = LHS1;
    }

    if (match(RHS1, m_APFloat(CR))) {
      // Keep predicate orientation with variable on operand 0.
    } else if (match(RHS0, m_APFloat(CR))) {
      CanonPredR = CmpInst::getSwappedPredicate(PredR);
      VarR = RHS1;
